class Solution:
    def makeTheIntegerZero(self, num1, num2):
        from collections import Counter
        for k in range(1, 61):
            target = num1 - k * num2
            if target < 0 or target < k:
                continue
            counts = Counter()
            t = target
            e = 0
            while t:
                if t & 1:
                    counts[e] += 1
                t >>= 1
                e += 1
            total = sum(counts.values())
            ok = None
            while True:
                if total == k:
                    ok = True
                    break
                if total > k:
                    ok = False
                    break
                candidates = [ex for ex in counts if counts[ex] > 0 and ex > 0]
                if not candidates:
                    ok = False
                    break
                hi = max(candidates)
                counts[hi] -= 1
                counts[hi - 1] = counts.get(hi - 1, 0) + 2
                total += 1
            if ok:
                return k
        return -1

