var makeTheIntegerZero = function(num1, num2) {
    const popcount = (x) => {
        let c = 0;
        while (x > 0) {
            c += x & 1;
            x = Math.floor(x / 2);
        }
        return c;
    };
    for (let k = 1; k <= 60; k++) {
        const target = num1 - k * num2;
        if (target < k) continue;
        if (popcount(target) <= k) return k;
    }
    return -1;
};
